INSERT INTO `sys_error` VALUES (67, '2026-05-03 19:32:23.341', '2026-05-03 19:32:23.341', NULL, '后端', '登陆失败! 用户名不存在或者密码错误! | 错误: 密码错误 \n 源文件:/mnt/d/game/hlddz/ddz/admin/server/api/v1/system/sys_user.go:68 \n 调用栈：github.com/flipped-aurora/gin-vue-admin/server/api/v1/system.(*BaseApi).Login\n	/mnt/d/game/hlddz/ddz/admin/server/api/v1/system/sys_user.go:68\ngithub.com/gin-gonic/gin.(*Context).Next\n	/home/adminis/go/pkg/mod/github.com/gin-gonic/gin@v1.10.0/context.go:185\ngithub.com/gin-gonic/gin.LoggerWithConfig.func1\n	/home/adminis/go/pkg/mod/github.com/gin-gonic/gin@v1.10.0/logger.go:249\ngithub.com/gin-gonic/gin.(*Context).Next\n	/home/adminis/go/pkg/mod/github.com/gin-gonic/gin@v1.10.0/context.go:185\ngithub.com/flipped-aurora/gin-vue-admin/server/initialize.Routers.GinRecovery.func2\n	/mnt/d/game/hlddz/ddz/admin/server/middleware/error.go:78\ngithub.com/gin-gonic/gin.(*Context).Next\n	/home/adminis/go/pkg/mod/github.com/gin-gonic/gin@v1.10.0/context.go:185\ngithub.com/gin-gonic/gin.(*Engine).handleHTTPRequest\n	/home/adminis/go/pkg/mod/github.com/gin-gonic/gin@v1.10.0/gin.go:633\ngithub.com/gin-gonic/gin.(*Engine).ServeHTTP\n	/home/adminis/go/pkg/mod/github.com/gin-gonic/gin@v1.10.0/gin.go:589\nnet/http.serverHandler.ServeHTTP\n	/home/adminis/go/pkg/mod/golang.org/toolchain@v0.0.1-go1.24.2.linux-amd64/src/net/http/server.go:3301\nnet/http.(*conn).serve\n	/home/adminis/go/pkg/mod/golang.org/toolchain@v0.0.1-go1.24.2.linux-amd64/src/net/http/server.go:2102 \n 最终调用方法:/mnt/d/game/hlddz/ddz/admin/server/api/v1/system/sys_user.go:68 (Login lines 27-99)\n----- 产生日志的方法代码如下 -----\nfunc (b *BaseApi) Login(c *gin.Context) {\n	var l systemReq.Login\n	err := c.ShouldBindJSON(&l)\n	if err != nil {\n		response.FailWithMessage(err.Error(), c)\n		return\n	}\n	err = utils.Verify(l, utils.LoginVerify)\n	if err != nil {\n		response.FailWithMessage(err.Error(), c)\n		return\n	}\n\n	key := c.ClientIP()\n	// 判断验证码是否开启\n	openCaptcha := global.GVA_CONFIG.Captcha.OpenCaptcha               // 是否开启防爆次数\n	openCaptchaTimeOut := global.GVA_CONFIG.Captcha.OpenCaptchaTimeOut // 缓存超时时间\n	v, ok := global.BlackCache.Get(key)\n	if !ok {\n		global.BlackCache.Set(key, 1, time.Second*time.Duration(openCaptchaTimeOut))\n	}\n\n	var oc bool = openCaptcha == 0 || openCaptcha < interfaceToInt(v)\n	if oc && (l.Captcha == \"\" || l.CaptchaId == \"\" || !store.Verify(l.CaptchaId, l.Captcha, true)) {\n		// 验证码次数+1\n		global.BlackCache.Increment(key, 1)\n		response.FailWithMessage(\"验证码错误\", c)\n		// 记录登录失败日志\n		loginLogService.CreateLoginLog(system.SysLoginLog{\n			Username:     l.Username,\n			Ip:           c.ClientIP(),\n			Agent:        c.Request.UserAgent(),\n			Status:       false,\n			ErrorMessage: \"验证码错误\",\n		})\n		return\n	}\n\n	u := &system.SysUser{Username: l.Username, Password: l.Password}\n	user, err := userService.Login(u)\n	if err != nil {\n		global.GVA_LOG.Error(\"登陆失败! 用户名不存在或者密码错误!\", zap.Error(err))\n		// 验证码次数+1\n		global.BlackCache.Increment(key, 1)\n		response.FailWithMessage(\"用户名不存在或者密码错误\", c)\n		// 记录登录失败日志\n		loginLogService.CreateLoginLog(system.SysLoginLog{\n			Username:     l.Username,\n			Ip:           c.ClientIP(),\n			Agent:        c.Request.UserAgent(),\n			Status:       false,\n			ErrorMessage: \"用户名不存在或者密码错误\",\n		})\n		return\n	}\n	if user.Enable != 1 {\n		global.GVA_LOG.Error(\"登陆失败! 用户被禁止登录!\")\n		// 验证码次数+1\n		global.BlackCache.Increment(key, 1)\n		response.FailWithMessage(\"用户被禁止登录\", c)\n		// 记录登录失败日志\n		loginLogService.CreateLoginLog(system.SysLoginLog{\n			Username:     l.Username,\n			Ip:           c.ClientIP(),\n			Agent:        c.Request.UserAgent(),\n			Status:       false,\n			ErrorMessage: \"用户被禁止登录\",\n			UserID:       user.ID,\n		})\n		return\n	}\n	b.TokenNext(c, *user)\n}', 'error', NULL, '未处理');
