INSERT INTO `sys_error` VALUES (206, '2026-05-06 15:17:50.700', '2026-05-06 15:17:50.700', NULL, '后端', '大模型生成失败! | 错误: 请先前往插件市场个人中心获取 AiPath 并填写到 config.yaml 中 \n 源文件:/mnt/d/game/hlddz/ddz/admin/server/api/v1/system/sys_auto_code.go:108 \n 调用栈：github.com/flipped-aurora/gin-vue-admin/server/api/v1/system.(*AutoCodeApi).LLMAuto\n	/mnt/d/game/hlddz/ddz/admin/server/api/v1/system/sys_auto_code.go:108\ngithub.com/gin-gonic/gin.(*Context).Next\n	/home/adminis/go/pkg/mod/github.com/gin-gonic/gin@v1.10.0/context.go:185\ngithub.com/gin-gonic/gin.LoggerWithConfig.func1\n	/home/adminis/go/pkg/mod/github.com/gin-gonic/gin@v1.10.0/logger.go:249\ngithub.com/gin-gonic/gin.(*Context).Next\n	/home/adminis/go/pkg/mod/github.com/gin-gonic/gin@v1.10.0/context.go:185\ngithub.com/flipped-aurora/gin-vue-admin/server/initialize.Routers.GinRecovery.func2\n	/mnt/d/game/hlddz/ddz/admin/server/middleware/error.go:78\ngithub.com/gin-gonic/gin.(*Context).Next\n	/home/adminis/go/pkg/mod/github.com/gin-gonic/gin@v1.10.0/context.go:185\ngithub.com/gin-gonic/gin.(*Engine).handleHTTPRequest\n	/home/adminis/go/pkg/mod/github.com/gin-gonic/gin@v1.10.0/gin.go:633\ngithub.com/gin-gonic/gin.(*Engine).ServeHTTP\n	/home/adminis/go/pkg/mod/github.com/gin-gonic/gin@v1.10.0/gin.go:589\nnet/http.serverHandler.ServeHTTP\n	/home/adminis/go/pkg/mod/golang.org/toolchain@v0.0.1-go1.24.2.linux-amd64/src/net/http/server.go:3301\nnet/http.(*conn).serve\n	/home/adminis/go/pkg/mod/golang.org/toolchain@v0.0.1-go1.24.2.linux-amd64/src/net/http/server.go:2102 \n 最终调用方法:/mnt/d/game/hlddz/ddz/admin/server/api/v1/system/sys_auto_code.go:108 (LLMAuto lines 87-113)\n----- 产生日志的方法代码如下 -----\nfunc (autoApi *AutoCodeApi) LLMAuto(c *gin.Context) {\n	var llm common.JSONMap\n	if err := c.ShouldBindJSON(&llm); err != nil {\n		response.FailWithMessage(err.Error(), c)\n		return\n	}\n\n	if shouldStreamLLM(c, llm) {\n		if err := autoApi.proxyLLMStream(c, llm); err != nil {\n			global.GVA_LOG.Error(\"大模型流式代理失败!\", zap.Error(err))\n			if c.Writer.Written() {\n				writeLLMStreamError(c, err)\n				return\n			}\n			response.FailWithMessage(err.Error(), c)\n		}\n		return\n	}\n\n	data, err := autoCodeService.LLMAuto(c.Request.Context(), llm)\n	if err != nil {\n		global.GVA_LOG.Error(\"大模型生成失败!\", zap.Error(err))\n		response.FailWithMessage(err.Error(), c)\n		return\n	}\n	response.OkWithData(data, c)\n}', 'error', NULL, '未处理');
