rg/toolchain@v0.0.1-go1.24.2.linux-amd64/src/net/http/server.go:2102 \n 最终调用方法:/mnt/d/game/hlddz/ddz/admin/server/api/v1/ddz/player.go:430 (GetCoinLogList lines 415-441)\n----- 产生日志的方法代码如下 -----\nfunc (api *DDZPlayerApi) GetCoinLogList(c *gin.Context) {\n        var req ddzReq.DDZCoinLogSearch\n        err := c.ShouldBindJSON(&req)\n        if err != nil {\n                response.FailWithMessage(err.Error(), c)\n                return\n        }\n        err = utils.Verify(req.PageInfo, utils.PageInfoVerify)\n        if err != nil {\n                response.FailWithMessage(err.Error(), c)\n                return\n        }\n\n        list, total, err := ddzPlayerService.GetCoinLogList(req)\n        if err != nil {\n                global.GVA_LOG.Error(\"获取货币流水失败!\", zap.Error(err))\n                response.FailWithMessage(\"获取货币流水失败: \"+err.Error(), c)\n                return\n        }\n\n        response.OkWithDetailed(response.PageResult{\n                List:     list,\n                Total:    total,\n                Page:     req.Page,\n                PageSize: req.PageSize,\n        }, \"获取成功\", c)\n}', 'error', NULL, '未处理');
INSERT INTO `sys_error` VALUES (215, '2026-05-08 14:55:41.893', '2026-05-08 14:55:41.893', NULL, '后端', '创建机器人失败 | 错误: Error 1062 (23000): Duplicate entry \'诗词歌赋\' for key \'ddz_players.idx_ddz_players_nickname\' \n 源文件:/mnt/d/game/hlddz/ddz/admin/server/service/ddz/player.go:961 \n 调用栈：github.com/flipped-aurora/gin-vue-admin/server/service/ddz.(*DDZPlayerService).GenerateRobots\n	/mnt/d/game/hlddz/ddz/admin/server/service/ddz/player.go:961\ngithub.com/flipped-aurora/gin-vue-admin/server/api/v1/ddz.(*DDZPlayerApi).GenerateRobots\n	/mnt/d/game/hlddz/ddz/admin/server/api/v1/ddz/player.go:466\ngithub.com/gin-gonic/gin.(*Context).Next\n	/home/adminis/go/pkg/mod/github.com/gin-gonic/gin@v1.10.0/context.go:185\ngithub.com/flipped-aurora/gin-vue-admin/server/router/ddz.(*DDZPlayerRouter).InitDDZPlayerRouter.OperationRecord.func1\n	/mnt/d/game/hlddz/ddz/admin/server/middleware/operation.go:93\ngithub.com/gin-gonic/gin.(*Context).Next\n	/home/adminis/go/pkg/mod/github.com/gin-gonic/gin@v1.10.0/context.go:185\ngithub.com/flipped-aurora/gin-vue-admin/server/initialize.Routers.CasbinHandler.func4\n	/mnt/d/game/hlddz/ddz/admin/server/middleware/casbin_rbac.go:82\ngithub.com/gin-gonic/gin.(*Context).Next\n	/home/adminis/go/pkg/mod/github.com/gin-gonic/gin@v1.10.0/context.go:185\ngithub.com/flipped-aurora/gin-vue-admin/server/initialize.Routers.JWTAuth.func3\n	/mnt/d/game/hlddz/ddz/admin/server/middleware/jwt.go:69\ngithub.com/gin-gonic/gin.(*Context).Next\n	/home/adminis/go/pkg/mod/github.com/gin-gonic/gin@v1.10.0/context.go:185\ngithub.com/gin-gonic/gin.LoggerWithConfig.func1\n	/home/adminis/go/pkg/mod/github.com/gin-gonic/gin@v1.10.0/logger.go:249\ngithub.com/gin-gonic/gin.(*Context).Next\n	/home/adminis/go/pkg/mod/github.com/gin-gonic/gin@v1.10.0/context.go:185\ngithub.com/flipped-aurora/gin-vue-admin/server/initialize.Routers.GinRecovery.func2\n	/mnt/d/game/hlddz/ddz/admin/server/middleware/error.go:78\ngithub.com/gin-gonic/gin.(*Context).Next\n	/home/adminis/go/pkg/mod/github.com/gin-gonic/gin@v1.10.0/context.go:185\ngithub.com/gin-gonic/gin.(*Engine).handleHTTPRequest\n	/home/adminis/go/pkg/mod/github.com/gin-gonic/gin@v1.10.0/gin.go:633\ngithub.com/gin-gonic/gin.(*Engine).ServeHTTP\n	/home/adminis/go/pkg/mod/github.com/gin-gonic/gin@v1.10.0/gin.go:589\nnet/http.serverHandler.ServeHTTP\n	/home/adminis/go/pkg/mod/golang.org/toolchain@v0.0.1-go1.24.2.linux-amd64/src/net/http/server.go:3301\nnet/http.(*conn).serve\n	/home/adminis/go/pkg/mod/golang.org/toolchain@v0.0.1-go1.24.2.linux-amd64/src/net/http/server.go:2102 \n 最终调用方法:/mnt/d/game/hlddz/ddz/admin/server/service/ddz/player.go:961 (GenerateRobots lines 842-981)\n----- 产生日志的方法代码如下 -----\nfunc (s *DDZPlayerService) GenerateRobots(count int) (ddzRes.DDZGenerateRobotsResponse, error) {\n        db := GetDDZDB()\n        if db == nil {\n                return ddzRes.DDZGenerateRobotsResponse{}, errors.New(\"数据库未连接\")\n        }\n\n        response := ddzRes.DDZGenerateRobotsResponse{\n                Robots: make([]ddzRes.DDZPlayerResponse, 0, count),\n        }\n\n        // 使用随机种子\n        r := rand.New(rand.NewSource(time.Now().UnixNano()))\n\n        // 获取头像文件列表\n        avatarFiles, err := s.getAvatarFiles()\n        if err != nil {\n                global.GVA_LOG.Warn(\"获取头像文件失败，使用默认头像\", zap.Error(err))\n                // 使用默认头像\n                avatarFiles = []string{\"avatar_1\", \"avatar_2\", \"avatar_3\", \"avatar_4\"}\n        }\n        global.GVA_LOG.Info(\"头像文件列表\", zap.Int(\"数量\", len(avatarFiles)))\n\n        // 已使用的昵称索引\n        usedNicknameIndices := make(map[int]bool)\n\n        for i := 0; i < count; i++ {\n                // 生成唯一的机器人ID: robot_ + 时间戳 + 随机数\n                robotID := fmt.Sprintf(\"robot_%d_%d\", time.Now().UnixNano()/1000000, r.Intn(10000))\n\n                // 从昵称库中随机选择一个未使用的昵称\n                var nickname string\n                var nicknameIndex int\n                maxAttempts := len(robotNicknames)\n                for attempt := 0; attempt < maxAttempts; attempt++ {\n                        nicknameIndex = r.Intn(len(robotNicknames))\n                        if !usedNicknameIndices[nicknameIndex] {\n                                usedNicknameIndices[nicknameIndex] = true\n                                nickname = robotNicknames[nicknameIndex]\n                                break\n                        }\n                }\n\n                // 如果所有昵称都被使用，添加随机后缀\n                if nickname == \"\" {\n                        nickname = robotNicknames[r.Intn(len(robotNicknames))] + fmt.Sprintf(\"%d\", r.Intn(100))\n                }\n\n                // 随机选择头像\n                var avatar string\n                if len(avatarFiles) > 0 {\n                        avatar = avatarFiles[r.Intn(len(avatarFiles))]\n                } else {\n                        avatar = fmt.Sprintf(\"avatar_%d\", r.Intn(4)+1)\n                }\n\n                // 随机性别\n                gender := uint8(r.Intn(3)) // 0-未知, 1-男, 2-女\n\n                // 随机初始金币 (1000-10000)\n                gold := int64(1000 + r.Intn(9001))\n\n                // 生成机器人Token (16位，比正常用户32位短)\n                robotToken := s.generateRobotToken(16)\n\n                // 创建机器人玩家\n                now := time.Now()\n                player := ddz.DDZPlayer{\n                        Username:   robotID,\n                        Nickname:   nickname,\n                        Avatar:     avatar,\n                        Gender:     gender,\n                        PlayerType: 2, // 机器人类型\n                        Gold:       gold,\n                        Diamond:    0,\n                        ArenaCoin:  0,\n                        Experience: 0,\n                        Level:      1,\n                        VIPLevel:   0,\n                        WinCount:   0,\n                        LoseCount:  0,\n                        Status:     1, // 正常状态\n                        CreatedAt:  now,\n                        UpdatedAt:  now,\n                }\n\n                // 使用事务创建玩家和账户\n                err := db.Transaction(func(tx *gorm.DB) error {\n                        // 创建玩家\n                        if err := tx.Create(&player).Error; err != nil {\n                                return err\n                        }\n\n                        // 计算Token过期时间（7天）\n                        tokenExpire := now.Add(7 * 24 * time.Hour)\n\n                        // 创建用户账户（模拟微信授权注册）\n                        account := ddz.DDZUserAccount{\n                                PlayerID:             uint(player.ID),\n                                WxOpenID:             fmt.Sprintf(\"robot_%s\", s.md5Hash(robotID)[:16]),\n                                WxUnionID:            fmt.Sprintf(\"union_%s\", s.md5Hash(robotID+nickname)[:16]),\n                                WxNickname:           nickname,\n                                WxAvatar:             avatar,\n                                LoginType:            2, // 微信登录类型\n                                Token:                robotToken,\n                                TokenExpireAt:        &tokenExpire,\n                                Status:               1, // 正常状态\n                                LastLoginAt:          &now,\n                                DeviceType:           \"robot\",\n                                LoginCount:           1,\n                        }\n\n                        if err := tx.Create(&account).Error; err != nil {\n                                return err\n                        }\n\n                        return nil\n                })\n\n                if err != nil {\n                        global.GVA_LOG.Error(\"创建机器人失败\", zap.Error(err), zap.String(\"robotID\", robotID))\n                        response.FailedCount++\n                        continue\n                }\n\n                response.SuccessCount++\n                response.Robots = append(response.Robots, s.toPlayerResponse(player))\n\n                global.GVA_LOG.Info(\"机器人创建成功\",\n                        zap.Uint64(\"playerID\", player.ID),\n                        zap.String(\"username\", robotID),\n                        zap.String(\"nickname\", nickname),\n                        zap.String(\"avatar\", avatar),\n                        zap.String(\"token\", robotToken))\n\n                // 短暂延迟以避免时间戳冲突\n                time.Sleep(time.Millisecond)\n        }\n\n        return response, nil\n}', 'error', NULL, '未处理');
