adminis/go/pkg/mod/golang.org/toolchain@v0.0.1-go1.24.2.linux-amd64/src/net/http/server.go:2102 \n 最终调用方法:/mnt/d/game/hlddz/ddz/admin/server/api/v1/ddz/game_log.go:171 (GetDealLogList lines 156-182)\n----- 产生日志的方法代码如下 -----\nfunc (api *DDZGameLogApi) GetDealLogList(c *gin.Context) {\n        var req ddzReq.DDZDealLogSearch\n        err := c.ShouldBindJSON(&req)\n        if err != nil {\n                response.FailWithMessage(err.Error(), c)\n                return\n        }\n        err = utils.Verify(req.PageInfo, utils.PageInfoVerify)\n        if err != nil {\n                response.FailWithMessage(err.Error(), c)\n                return\n        }\n\n        list, total, err := ddzGameLogService.GetDealLogList(req)\n        if err != nil {\n                global.GVA_LOG.Error(\"获取发牌日志列表失败!\", zap.Error(err))\n                response.FailWithMessage(\"获取发牌日志列表失败\", c)\n                return\n        }\n\n        response.OkWithDetailed(response.PageResult{\n                List:     list,\n                Total:    total,\n                Page:     req.Page,\n                PageSize: req.PageSize,\n        }, \"获取成功\", c)\n}', 'error', NULL, '未处理');
