INSERT INTO `sys_operation_records` VALUES (283, '2026-05-09 16:54:43.928', '2026-05-09 16:54:43.928', NULL, '127.0.0.1', 'PUT', '/ddz/roomConfig/update', 200, 54852707, 'Mozilla/5.0 (Windows NT 10.0; Win64; x64) AppleWebKit/537.36 (KHTML, like Gecko) Chrome/147.0.0.0 Safari/537.36', '', '{\"ID\":1,\"roomName\":\"新手场\",\"roomType\":2,\"roomTypeName\":\"初级场\",\"roomCategory\":2,\"roomCategoryName\":\"竞技场\",\"baseScore\":1,\"multiplier\":1,\"minGold\":1000,\"maxGold\":50000,\"minArenaCoin\":100,\"maxArenaCoin\":0,\"entryGold\":1000,\"bgImageNum\":2,\"botEnabled\":1,\"botCount\":5,\"feeRate\":0,\"maxRound\":20,\"timeoutSeconds\":30,\"status\":1,\"statusText\":\"开启\",\"sortOrder\":1,\"description\":\"适合新手玩家,底分1,最低1000金币入场\",\"createdAt\":\"2026-04-26 09:27:51\",\"updatedAt\":\"2026-05-07 06:55:58\",\"matchTimeRanges\":\"[{\\\"end\\\":\\\"23:59\\\",\\\"start\\\":\\\"00:00\\\"}]\",\"matchRoundDuration\":5,\"matchRoundCount\":3,\"maxPlayers\":90,\"minPlayers\":30,\"championRewardId\":0,\"eliminationRules\":\"[60,30,18,9,3]\",\"rankWaitSeconds\":30,\"minMatchPlayers\":1}', '{\"code\":0,\"data\":{},\"msg\":\"更新成功\"}', 1);
INSERT INTO `sys_user_agreement` VALUES (1, '2026-04-22 10:48:00.000', '2026-04-22 10:48:00.000', NULL, '用户协议', '<h1>用户协议</h1>\n<p><strong>最后更新日期：2026年4月22日</strong></p>\n\n<h2>一、服务条款的确认和接纳</h2>\n<p>欢迎使用我们的斗地主游戏服务。在使用本服务前，请您仔细阅读以下条款。使用本服务即表示您同意遵守这些条款。</p>\n\n<h2>二、用户注册</h2>\n<p>1. 用户应按照注册页面提示完成注册流程。您应当对注册信息的真实性、合法性负责。</p>\n<p>2. 您注册成功后，将获得一个账号和密码。您应妥善保管账号和密码，并对以您的账号进行的所有活动负责。</p>\n\n<h2>三、使用规则</h2>\n<p>1. 用户不得利用本服务从事违法活动。</p>\n<p>2. 用户不得干扰本服务的正常运行。</p>\n<p>3. 用户不得侵犯他人的合法权益。</p>\n\n<h2>四、知识产权</h2>\n<p>本游戏的所有内容，包括但不限于文字、图片、音频、视频、软件等，均受知识产权法律保护。</p>\n\n<h2>五、免责声明</h2>\n<p>1. 本服务按\"现状\"提供，不提供任何形式的担保。</p>\n<p>2. 对于因使用本服务而产生的任何直接或间接损失，我们不承担责任。</p>\n\n<h2>六、条款修改</h2>\n<p>我们保留随时修改本协议的权利。修改后的协议将在本页面公布，敬请关注。</p>\n\n<h2>七、联系我们</h2>\n<p>如有任何问题，请通过游戏内的客服系统联系我们。</p>', 'v1.0.0', 1, 1);
